/**
 * One row of chart data: keys are field names, values are numbers or category
 * labels. The optional `fill` sets a per-row color (per-bar / per-slice), used
 * by the categorical single-series charts — parity with the React `ChartDatum`.
 */
export type ChartDatum = Record<string, string | number> & { fill?: string };

/** @deprecated Back-compat alias. Prefer {@link ChartDatum}. */
export type Datum = ChartDatum;

/** Inner padding between the SVG edge and the plotting area. */
export interface Margin {
  top: number;
  right: number;
  bottom: number;
  left: number;
}

/**
 * Per-series visual config. Both `label` and `color` are **optional** — parity
 * with the React `ChartConfig` primitive. When omitted, charts fall back to a
 * title-cased key (label) and the cycling palette `--chart-1..5` (color).
 */
export interface ChartSeriesConfig {
  /** Legend / tooltip label. Defaults to a title-cased key. */
  label?: string;
  /** CSS color or token, e.g. `'var(--chart-1)'`. Defaults to the palette. */
  color?: string;
  /** Angular-only extension: formatter preset, e.g. `'currency:BRL' | 'percent' | 'compact'`. */
  format?: string;
}

/** @deprecated Back-compat alias. Prefer {@link ChartSeriesConfig}. */
export type SeriesConfigEntry = ChartSeriesConfig;

/** Maps a data field name to its series config. JSON-serializable (generative-UI ready). */
export type ChartConfig = Record<string, ChartSeriesConfig>;

/** Curve interpolation for area / line series (parity with recharts `type`). */
export type CurveType = 'natural' | 'monotone' | 'linear' | 'step';

/** Polar grid shape for the radar chart. */
export type GridType = 'polygon' | 'circle';

export const DEFAULT_MARGIN: Margin = {
  top: 8,
  right: 8,
  bottom: 24,
  left: 40,
};

/** Title-case a field key for a default label, e.g. `unique_users` → `Unique Users`. */
export function titleCaseKey(key: string): string {
  return key.replace(/[-_]/g, ' ').replace(/\b\w/g, (c) => c.toUpperCase());
}

/** The cycling categorical palette token for index `i`. */
export function paletteColor(i: number): string {
  return `var(--chart-${(i % 5) + 1})`;
}

import { format as d3Format } from 'd3-format';

const number = d3Format(',');
const compact = d3Format('.3~s');
const percent = d3Format('.1~%');

/**
 * Format a numeric value using a named preset. Presets are JSON-friendly
 * strings (no functions) so the styled layer's config stays serializable
 * for generative UI. Unknown presets fall back to the default number format.
 *
 * Supported: 'number' (default) | 'currency:<ISO>' | 'percent' | 'compact'.
 */
export function formatValue(value: number, preset = 'number'): string {
  if (preset.startsWith('currency:')) {
    const currency = preset.slice('currency:'.length) || 'USD';
    return new Intl.NumberFormat('en-US', {
      style: 'currency',
      currency,
    }).format(value);
  }
  switch (preset) {
    case 'percent':
      return percent(value);
    case 'compact':
      return compact(value).toUpperCase();
    case 'number':
      return number(value);
    default:
      return number(value);
  }
}

import { scaleBand, scaleLinear, scalePoint } from 'd3-scale';

/** Continuous numeric scale (thin wrapper over d3-scale). */
export function linearScale(
  domain: readonly [number, number],
  range: readonly [number, number],
): (value: number) => number {
  return scaleLinear()
    .domain([...domain])
    .range([...range]);
}

/** Categorical position scale; categories land at discrete points across the range. */
export function pointScale(
  categories: readonly string[],
  range: readonly [number, number],
): (value: string) => number {
  const scale = scalePoint<string>()
    .domain([...categories])
    .range([...range])
    .padding(0);
  return (value: string) => scale(value) ?? 0;
}

/** A band scale: maps a category to its slot start, plus the slot geometry. */
export interface BandScale {
  (value: string): number;
  /** Width of each category's band (where bars are drawn). */
  bandwidth: number;
  /** Distance between adjacent band starts (bandwidth + padding). */
  step: number;
}

/** Categorical band scale for bars — each category gets a slot of `bandwidth`. */
export function bandScale(
  categories: readonly string[],
  range: readonly [number, number],
  padding = 0.2,
): BandScale {
  const scale = scaleBand<string>()
    .domain([...categories])
    .range([...range])
    .padding(padding);
  const fn = ((value: string) => scale(value) ?? 0) as BandScale;
  fn.bandwidth = scale.bandwidth();
  fn.step = scale.step();
  return fn;
}

/**
 * Round a raw maximum up to the same axis bound recharts (the React edition)
 * picks, so both editions render identical Y axes for the same data. Port of
 * recharts' `getAdaptiveStep` for the [0, max] case: the rough step's
 * mantissa is rounded up in 0.05 increments (0.1 for single-digit steps) and
 * the bound rebuilt from that step. E.g. 305 over 4 intervals -> rough step
 * 76.25 -> step 80 -> bound 320 (recharts renders 0/80/160/240/320); a round
 * max like 100 stays 100 (step 25).
 */
export function niceMax(rawMax: number, intervals = 4): number {
  if (rawMax <= 0) return 1;
  const roughStep = rawMax / intervals;
  const digitCount = Math.floor(Math.log10(Math.abs(roughStep))) + 1;
  const digitCountValue = Math.pow(10, digitCount);
  const ratio = roughStep / digitCountValue;
  const ratioScale = digitCount !== 1 ? 0.05 : 0.1;
  const step = Math.ceil(ratio / ratioScale - 1e-9) * ratioScale * digitCountValue;
  // Guard float drift (e.g. 0.30000000000000004) before rebuilding the bound.
  const rounded = Math.round(step * 1e9) / 1e9;
  return Math.round(rounded * intervals * 1e9) / 1e9;
}

import {
  area as d3Area,
  line as d3Line,
  curveLinear,
  curveMonotoneX,
  curveNatural,
  curveStep,
  type CurveFactory,
} from 'd3-shape';
import type { CurveType } from './types';

export interface XYPoint {
  x: number;
  y: number;
}

/** A point with an explicit lower/upper Y, used for stacked area bands. */
export interface BandPoint {
  x: number;
  y0: number;
  y1: number;
}

const CURVES: Record<CurveType, CurveFactory> = {
  natural: curveNatural,
  monotone: curveMonotoneX,
  linear: curveLinear,
  step: curveStep,
};

/** Resolve a {@link CurveType} preset to its d3 curve factory. */
export function curveFactory(type: CurveType = 'linear'): CurveFactory {
  return CURVES[type] ?? curveLinear;
}

/** SVG `d` for a line through the given points. Empty string if no points. */
export function linePath(
  points: readonly XYPoint[],
  curve: CurveType = 'linear',
): string {
  const gen = d3Line<XYPoint>()
    .x((p) => p.x)
    .y((p) => p.y)
    .curve(curveFactory(curve));
  return gen([...points]) ?? '';
}

/** SVG `d` for an area between the points and a horizontal baseline. */
export function areaPath(
  points: readonly XYPoint[],
  baseline: number,
  curve: CurveType = 'linear',
): string {
  const gen = d3Area<XYPoint>()
    .x((p) => p.x)
    .y0(baseline)
    .y1((p) => p.y)
    .curve(curveFactory(curve));
  return gen([...points]) ?? '';
}

/** SVG `d` for a stacked area band (explicit lower + upper Y per point). */
export function areaBandPath(
  points: readonly BandPoint[],
  curve: CurveType = 'linear',
): string {
  const gen = d3Area<BandPoint>()
    .x((p) => p.x)
    .y0((p) => p.y0)
    .y1((p) => p.y1)
    .curve(curveFactory(curve));
  return gen([...points]) ?? '';
}

/** Per-corner radii for {@link roundedRectPath}: `[topLeft, topRight, bottomRight, bottomLeft]`. */
export type CornerRadii = [number, number, number, number];

/**
 * SVG `d` for a rectangle with independent corner radii. Mirrors the recharts
 * `radius` array `[tl, tr, br, bl]`, so a bar can round only its top (or only
 * the outer corners of a stack). Radii are clamped to the rect's half-extent.
 */
export function roundedRectPath(
  x: number,
  y: number,
  w: number,
  h: number,
  radii: CornerRadii,
): string {
  const lim = Math.min(w, h) / 2;
  const [tl, tr, br, bl] = radii.map((r) => Math.max(0, Math.min(r, lim))) as CornerRadii;
  return (
    `M${x + tl},${y}` +
    `H${x + w - tr}` +
    (tr ? `A${tr},${tr} 0 0 1 ${x + w},${y + tr}` : '') +
    `V${y + h - br}` +
    (br ? `A${br},${br} 0 0 1 ${x + w - br},${y + h}` : '') +
    `H${x + bl}` +
    (bl ? `A${bl},${bl} 0 0 1 ${x},${y + h - bl}` : '') +
    `V${y + tl}` +
    (tl ? `A${tl},${tl} 0 0 1 ${x + tl},${y}` : '') +
    'Z'
  );
}

/** A series registered with the chart context, contributing values to the shared Y domain. */
export interface SeriesReg {
  key: string;
  /** Live accessor — reads current data so the domain stays reactive. */
  values: () => readonly number[];
}

/** Shared Y domain [0, max] across all registered series. Falls back to [0, 1]. */
export function computeYDomain(
  registrations: readonly SeriesReg[],
): [number, number] {
  let max = 0;
  let seen = false;
  for (const reg of registrations) {
    for (const v of reg.values()) {
      seen = true;
      if (v > max) max = v;
    }
  }
  return [0, seen && max > 0 ? max : 1];
}

/**
 * Stacked Y domain [0, max] where `max` is the largest per-row SUM across every
 * registered series — so a stacked bar/area chart's axis covers the full stack,
 * not just the tallest single series. Falls back to [0, 1].
 */
export function computeStackedYDomain(
  registrations: readonly SeriesReg[],
): [number, number] {
  const columns = registrations.map((r) => r.values());
  const rows = columns.reduce((m, c) => Math.max(m, c.length), 0);
  let max = 0;
  for (let i = 0; i < rows; i++) {
    let sum = 0;
    for (const col of columns) sum += Number(col[i] ?? 0);
    if (sum > max) max = sum;
  }
  return [0, max > 0 ? max : 1];
}

import { computed, Injectable, signal } from '@angular/core';
import {
  computeStackedYDomain,
  computeYDomain,
  type SeriesReg,
} from './domain';
import { linearScale, niceMax, pointScale } from './scales';
import { DEFAULT_MARGIN, type Datum, type Margin } from './types';

/**
 * Reactive hub shared by a chart frame and its child series/axes via DI.
 * The frame writes dimensions + data; series self-register their values so
 * the frame can compute a shared domain; scales are derived `computed`s.
 */
@Injectable()
export class ChartContext {
  readonly width = signal(0);
  readonly height = signal(0);
  readonly margin = signal<Margin>(DEFAULT_MARGIN);
  readonly data = signal<readonly Datum[]>([]);
  readonly xKey = signal<string>('');

  /** When true, the Y domain covers per-row stacked sums (bar/area stacking). */
  readonly stacked = signal(false);

  private readonly registry = signal<readonly SeriesReg[]>([]);

  register(reg: SeriesReg): void {
    this.registry.update((r) => [...r.filter((s) => s.key !== reg.key), reg]);
  }

  unregister(key: string): void {
    this.registry.update((r) => r.filter((s) => s.key !== key));
  }

  /** Registered series keys in registration order — used for grouped layouts. */
  readonly seriesKeys = computed(() => this.registry().map((s) => s.key));

  readonly innerWidth = computed(() =>
    Math.max(0, this.width() - this.margin().left - this.margin().right),
  );
  readonly innerHeight = computed(() =>
    Math.max(0, this.height() - this.margin().top - this.margin().bottom),
  );

  // Plot bounds in absolute SVG coordinates. Scales map into these so the
  // margins become real gutters (Y labels on the left, X labels below) instead
  // of dead space — without needing a `<g transform="translate(...)">` wrapper.
  readonly plotLeft = computed(() => this.margin().left);
  readonly plotRight = computed(() =>
    Math.max(this.margin().left, this.width() - this.margin().right),
  );
  readonly plotTop = computed(() => this.margin().top);
  readonly plotBottom = computed(() =>
    Math.max(this.margin().top, this.height() - this.margin().bottom),
  );

  readonly yDomain = computed<[number, number]>(() => {
    const [min, rawMax] = this.stacked()
      ? computeStackedYDomain(this.registry())
      : computeYDomain(this.registry());
    // Round the upper bound to a readable value so axis ticks land on
    // clean numbers (e.g. 305 -> 500 -> ticks 0/125/250/375/500).
    return [min, niceMax(rawMax)];
  });

  /**
   * Cumulative base value for `key` at each row when stacking — the sum of all
   * series registered *before* it. Series register in template/config order, so
   * this is the stack order. Returns zeros when not stacking.
   */
  stackBaseFor(key: string): readonly number[] {
    const keys = this.seriesKeys();
    const idx = keys.indexOf(key);
    const data = this.data();
    if (!this.stacked() || idx <= 0) return data.map(() => 0);
    const below = keys.slice(0, idx);
    return data.map((row) =>
      below.reduce((sum, k) => sum + Number(row[k] ?? 0), 0),
    );
  }

  readonly yScale = computed(() =>
    linearScale(this.yDomain(), [this.plotBottom(), this.plotTop()]),
  );

  readonly xScale = computed(() =>
    pointScale(
      this.data().map((d) => String(d[this.xKey()])),
      [this.plotLeft(), this.plotRight()],
    ),
  );
}

import { computed, Directive, inject } from '@angular/core';
import { ChartContext } from './chart-context';
import { formatValue } from './format';

/** Pure: `count` evenly spaced tick values from 0..max inclusive. */
export function computeTicks(max: number, count: number): number[] {
  if (max <= 0 || count <= 0) return [0];
  const step = max / count;
  return Array.from(
    { length: count + 1 },
    (_, i) => Math.round(i * step * 1e6) / 1e6,
  );
}

interface YTick {
  value: number;
  y: number;
  label: string;
}

interface XTick {
  label: string;
  x: number;
}

/** Y axis: tick values + pixel Y + formatted label, read from the context. */
@Directive({
  selector: 'g[yAxis]',
  host: { 'data-slot': 'y-axis' },
  exportAs: 'yAxis',
})
export class YAxis {
  private readonly ctx = inject(ChartContext);
  readonly count = 4;
  readonly format = '';

  /** X position for right-aligned tick labels, inside the left gutter. */
  readonly labelX = computed(() => Math.max(0, this.ctx.plotLeft() - 6));

  readonly ticks = computed<YTick[]>(() => {
    const [, max] = this.ctx.yDomain();
    const y = this.ctx.yScale();
    return computeTicks(max, this.count).map((value) => ({
      value,
      y: y(value),
      label: formatValue(value, this.format || 'number'),
    }));
  });
}

/** X axis: category labels + pixel X, read from the context. */
@Directive({
  selector: 'g[xAxis]',
  host: { 'data-slot': 'x-axis' },
  exportAs: 'xAxis',
})
export class XAxis {
  private readonly ctx = inject(ChartContext);

  /** Y baseline for tick labels, inside the bottom gutter. */
  readonly labelY = computed(() => this.ctx.plotBottom() + 16);

  readonly ticks = computed<XTick[]>(() => {
    const x = this.ctx.xScale();
    return this.ctx
      .data()
      .map((d) => String(d[this.ctx.xKey()]))
      .map((label) => ({ label, x: x(label) }));
  });
}

import {
  afterNextRender,
  computed,
  Directive,
  effect,
  ElementRef,
  inject,
  input,
} from '@angular/core';
import { ChartContext } from './chart-context';
import type { Datum, Margin } from './types';
import { DEFAULT_MARGIN } from './types';

/**
 * Root of a headless chart. Apply to an `<svg>`. Provides a `ChartContext`
 * to all descendant series/axes, mirrors `data`/`xKey` into it, and tracks
 * the element's size via ResizeObserver (client-only). SSR renders with a
 * `viewBox` so the chart is meaningful before hydration.
 *
 * @example
 * ```html
 * <svg chartFrame [data]="data" xKey="month"><svg:path [area]="'sales'"/></svg>
 * ```
 */
@Directive({
  selector: 'svg[chartFrame]',
  providers: [ChartContext],
  host: {
    'data-slot': 'chart-frame',
    preserveAspectRatio: 'none',
    '[attr.viewBox]': 'viewBox()',
  },
})
export class ChartFrame {
  private readonly ctx = inject(ChartContext);
  private readonly el = inject<ElementRef<SVGSVGElement>>(ElementRef);

  readonly data = input.required<readonly Datum[]>();
  readonly xKey = input.required<string>();
  readonly margin = input<Margin>(DEFAULT_MARGIN);
  /** Stack series within each category (drives the shared Y domain). */
  readonly stacked = input<boolean>(false);

  readonly viewBox = computed(
    () => `0 0 ${this.ctx.width()} ${this.ctx.height()}`,
  );

  constructor() {
    effect(() => {
      this.ctx.data.set(this.data());
      this.ctx.xKey.set(this.xKey());
      this.ctx.margin.set(this.margin());
      this.ctx.stacked.set(this.stacked());
    });

    afterNextRender(() => {
      const node = this.el.nativeElement;
      if (typeof ResizeObserver === 'undefined') {
        const rect = node.getBoundingClientRect();
        this.ctx.width.set(rect.width);
        this.ctx.height.set(rect.height);
        return;
      }
      const ro = new ResizeObserver((entries) => {
        const box = entries[0]?.contentRect;
        if (box) {
          this.ctx.width.set(box.width);
          this.ctx.height.set(box.height);
        }
      });
      ro.observe(node);
    });
  }
}

import { computed, Directive, inject } from '@angular/core';
import { ChartContext } from './chart-context';
import { computeTicks } from './axis';

interface GridLine {
  y: number;
  x1: number;
  x2: number;
}

/**
 * Horizontal gridlines aligned to the Y ticks. Apply to a `<g>` inside a
 * `[chartFrame]` SVG. Exposes `lines()` (each spanning the plot width); the
 * styled layer draws them so the headless layer stays visual-free.
 */
@Directive({
  selector: 'g[cartesianGrid]',
  host: { 'data-slot': 'cartesian-grid' },
  exportAs: 'cartesianGrid',
})
export class CartesianGrid {
  private readonly ctx = inject(ChartContext);

  readonly lines = computed<GridLine[]>(() => {
    const [, max] = this.ctx.yDomain();
    const y = this.ctx.yScale();
    const x1 = this.ctx.plotLeft();
    const x2 = this.ctx.plotRight();
    return computeTicks(max, 4).map((value) => ({ y: y(value), x1, x2 }));
  });
}

import {
  computed,
  Directive,
  effect,
  ElementRef,
  inject,
  input,
  signal,
} from '@angular/core';
import { ChartContext } from './chart-context';

/** Pixel point in the chart's viewBox (== rendered) coordinate space. */
export interface TooltipPoint {
  x: number;
  y: number;
}

/**
 * Pointer-tracking tooltip controller for the cartesian charts. Compose it on
 * the same `<svg>` as `[chartFrame]`; it snaps to the nearest category as the
 * pointer moves and exposes the active index, the cursor X, and the pointer
 * position so the styled layer can render a floating card, a cursor line, and
 * per-series markers. The headless layer stays visual-free — it only computes.
 *
 * @example
 * ```html
 * <svg chartFrame chartTooltip #tip="chartTooltip" [data]="data()" [xKey]="xKey()">…</svg>
 * @if (tip.activeIndex() !== null) { <div class="…" [style.left.px]="tip.activeX()">…</div> }
 * ```
 */
@Directive({
  selector: 'svg[chartTooltip]',
  exportAs: 'chartTooltip',
  host: {
    '(pointermove)': 'onMove($event)',
    '(pointerleave)': 'onLeave()',
  },
})
export class ChartTooltip {
  private readonly ctx = inject(ChartContext);
  private readonly el = inject<ElementRef<SVGSVGElement>>(ElementRef);

  /** Index of the category under the pointer, or `null` when not hovering. */
  readonly activeIndex = signal<number | null>(null);
  /** Raw pointer position in viewBox px (for positioning the floating card). */
  readonly pointer = signal<TooltipPoint>({ x: 0, y: 0 });

  private readonly categories = computed(() =>
    this.ctx.data().map((d) => String(d[this.ctx.xKey()])),
  );

  /** Cursor X (viewBox px) at the active category center. */
  readonly activeX = computed(() => {
    const i = this.activeIndex();
    const cats = this.categories();
    if (i === null || !cats.length) return 0;
    return this.ctx.xScale()(cats[i] ?? '');
  });

  /** The active data row, or `undefined`. */
  readonly activeRow = computed(() => {
    const i = this.activeIndex();
    return i === null ? undefined : this.ctx.data()[i];
  });

  /** Top / bottom of the plotting band (viewBox px) — for the cursor line. */
  readonly plotTop = computed(() => this.ctx.plotTop());
  readonly plotBottom = computed(() => this.ctx.plotBottom());

  /** viewBox dimensions (px) — the styled tooltip card maps these to DOM px. */
  readonly width = computed(() => this.ctx.width());
  readonly height = computed(() => this.ctx.height());

  /** Y (viewBox px) for `key`'s value at the active index — for series markers. */
  valueY(key: string): number {
    const row = this.activeRow();
    if (!row) return 0;
    return this.ctx.yScale()(Number(row[key] ?? 0));
  }

  onMove(event: PointerEvent): void {
    const rect = this.el.nativeElement.getBoundingClientRect();
    if (rect.width === 0 || rect.height === 0) return;
    const scaleX = this.ctx.width() / rect.width || 1;
    const scaleY = this.ctx.height() / rect.height || 1;
    const lx = (event.clientX - rect.left) * scaleX;
    const ly = (event.clientY - rect.top) * scaleY;
    const cats = this.categories();
    if (!cats.length) return;
    const xScale = this.ctx.xScale();
    let nearest = 0;
    let best = Infinity;
    for (let i = 0; i < cats.length; i++) {
      const dx = Math.abs(xScale(cats[i]) - lx);
      if (dx < best) {
        best = dx;
        nearest = i;
      }
    }
    this.activeIndex.set(nearest);
    this.pointer.set({ x: lx, y: ly });
  }

  onLeave(): void {
    this.activeIndex.set(null);
  }
}

/**
 * Boundary-aware placement for the floating tooltip card. Apply it to the
 * absolutely-positioned card `<div>` (a sibling of the `<svg>`, inside the
 * `position: relative` wrapper) and pass the `chartTooltip` instance:
 *
 * ```html
 * <div class="absolute …" [chartTooltipCard]="tip"> … </div>
 * ```
 *
 * It mirrors the React (recharts) behavior: the card follows the pointer but is
 * kept inside the chart — it flips to the left of the cursor near the right edge
 * and is clamped on both axes — so it never overflows the artifact (no stray
 * scrollbar, never hidden behind the border). Angular-native: the headless
 * directive computes the pointer/viewBox; this one measures the rendered card +
 * its offset parent and positions imperatively via an `effect`.
 */
@Directive({
  selector: '[chartTooltipCard]',
})
export class ChartTooltipCard {
  private readonly el = inject<ElementRef<HTMLElement>>(ElementRef);
  /** The `chartTooltip` instance (pass `[chartTooltipCard]="tip"`). */
  readonly tip = input.required<ChartTooltip>({ alias: 'chartTooltipCard' });

  /** Gap from the cursor and minimum inset from the wrapper edges (DOM px). */
  private readonly GAP = 12;
  private readonly PAD = 8;

  constructor() {
    effect(() => {
      const tip = this.tip();
      const p = tip.pointer();
      if (tip.activeIndex() === null) return;

      const card = this.el.nativeElement;
      const parent = card.offsetParent as HTMLElement | null;
      if (!parent) return;

      const pw = parent.clientWidth || 1;
      const ph = parent.clientHeight || 1;
      // Pointer is in viewBox px; map it into the wrapper's DOM px so the card
      // lines up with the rendered (scaled) chart.
      const domX = (p.x / (tip.width() || 1)) * pw;
      const domY = (p.y / (tip.height() || 1)) * ph;
      const cw = card.offsetWidth;
      const ch = card.offsetHeight;

      // Prefer the right of the cursor; flip left when it would overflow.
      let left = domX + this.GAP;
      if (left + cw > pw - this.PAD) left = domX - this.GAP - cw;
      left = Math.max(this.PAD, Math.min(left, pw - cw - this.PAD));

      // Vertically center on the cursor, clamped inside the wrapper.
      let top = domY - ch / 2;
      top = Math.max(this.PAD, Math.min(top, ph - ch - this.PAD));

      card.style.left = `${left}px`;
      card.style.top = `${top}px`;
      card.style.transform = 'none';
    });
  }
}

import {
  computed,
  Directive,
  inject,
  input,
  type OnDestroy,
  type OnInit,
} from '@angular/core';
import { ChartContext } from './chart-context';
import { areaBandPath, areaPath, type XYPoint } from './shape';
import type { CurveType, Datum } from './types';

/** Pure: project data through the scales into an area `d` string. */
export function computeAreaPath(
  data: readonly Datum[],
  xKey: string,
  yKey: string,
  xScale: (v: string) => number,
  yScale: (v: number) => number,
  baseline: number,
  curve: CurveType = 'linear',
): string {
  if (data.length === 0) return '';
  const points = data.map((d) => ({
    x: xScale(String(d[xKey])),
    y: yScale(Number(d[yKey])),
  }));
  return areaPath(points, baseline, curve);
}

/**
 * Renders a filled area for one series on a `<path>` inside a `[chartFrame]` SVG.
 * Self-registers its values so the frame's shared Y domain includes this series.
 * Honours the frame's `stacked` mode (each area sits on the cumulative sum of the
 * series below it) and exposes `points()` for tooltip markers.
 *
 * @example `<svg:path [area]="'sales'" color="var(--chart-1)" curve="natural"></svg:path>`
 */
@Directive({
  selector: 'path[area]',
  exportAs: 'area',
  host: {
    'data-slot': 'area',
    '[attr.d]': 'd()',
    '[attr.fill]': 'color()',
    '[attr.fill-opacity]': 'fillOpacity()',
  },
})
export class Area implements OnInit, OnDestroy {
  private readonly ctx = inject(ChartContext);

  /** Data field this area represents (the directive's input value). */
  readonly dataKey = input.required<string>({ alias: 'area' });
  readonly color = input<string>('currentColor');
  readonly fillOpacity = input<number>(0.25);
  readonly curve = input<CurveType>('linear');

  readonly d = computed(() => {
    const data = this.ctx.data();
    if (data.length === 0) return '';
    const xKey = this.ctx.xKey();
    const key = this.dataKey();
    const xScale = this.ctx.xScale();
    const yScale = this.ctx.yScale();

    if (this.ctx.stacked()) {
      const base = this.ctx.stackBaseFor(key);
      return areaBandPath(
        data.map((d, i) => {
          const lo = base[i] ?? 0;
          const hi = lo + Number(d[key] ?? 0);
          return {
            x: xScale(String(d[xKey])),
            y0: yScale(lo),
            y1: yScale(hi),
          };
        }),
        this.curve(),
      );
    }

    return computeAreaPath(
      data,
      xKey,
      key,
      (v) => xScale(v),
      (v) => yScale(v),
      yScale(0),
      this.curve(),
    );
  });

  /** Top-edge pixel points (cumulative when stacked) — for tooltip markers. */
  readonly points = computed<XYPoint[]>(() => {
    const data = this.ctx.data();
    const xKey = this.ctx.xKey();
    const key = this.dataKey();
    const xScale = this.ctx.xScale();
    const yScale = this.ctx.yScale();
    const base = this.ctx.stacked()
      ? this.ctx.stackBaseFor(key)
      : data.map(() => 0);
    return data.map((d, i) => ({
      x: xScale(String(d[xKey])),
      y: yScale((base[i] ?? 0) + Number(d[key] ?? 0)),
    }));
  });

  ngOnInit(): void {
    const key = this.dataKey();
    this.ctx.register({
      key,
      values: () => this.ctx.data().map((row) => Number(row[key])),
    });
  }

  ngOnDestroy(): void {
    this.ctx.unregister(this.dataKey());
  }
}

