import {
  computed,
  Directive,
  inject,
  input,
  type OnDestroy,
  type OnInit,
} from '@angular/core';
import { computeTicks } from './axis';
import { ChartContext } from './chart-context';
import { formatValue } from './format';
import { bandScale, linearScale } from './scales';
import { roundedRectPath, type CornerRadii } from './shape';

/** A category tick: label plus its anchor pixel position. */
export interface BarCategoryTick {
  label: string;
  x: number;
  y: number;
}

/** A numeric value tick: value, label, and anchor pixel position. */
export interface BarValueTick {
  value: number;
  label: string;
  x: number;
  y: number;
}

/** A grid line in pixel coordinates. */
export interface BarGridLine {
  x1: number;
  y1: number;
  x2: number;
  y2: number;
}

export interface BarRect {
  x: number;
  y: number;
  width: number;
  height: number;
  /** Rounded-corner path `d` (honours `radius` + stack position + orientation). */
  d: string;
  /** Per-row color override (the datum's `fill`), if any. */
  fill?: string;
  /** The category label and numeric value (for labels / tooltip). */
  name: string;
  value: number;
}

/**
 * Computes bar rects for one series on a `<g>` inside a `[chartFrame]` SVG.
 * Supports grouped (side-by-side) and stacked layouts, vertical and horizontal
 * orientation, rounded corners (`radius`), and per-row `fill`. Self-registers
 * values for the shared domain.
 *
 * @example
 * ```html
 * <svg:g [bar]="'sales'" [radius]="8" #b="bar">
 *   @for (r of b.bars(); track $index) { <svg:path [attr.d]="r.d" /> }
 * </svg:g>
 * ```
 */
@Directive({
  selector: 'g[bar]',
  host: { 'data-slot': 'bar' },
  exportAs: 'bar',
})
export class Bar implements OnInit, OnDestroy {
  private readonly ctx = inject(ChartContext);

  readonly dataKey = input.required<string>({ alias: 'bar' });
  /** Corner radius (px). Rounds the top (vertical) / right (horizontal) corners. */
  readonly radius = input<number>(0);
  /** Render horizontal bars (categories on Y, values on X). */
  readonly horizontal = input<boolean>(false);

  readonly bars = computed<BarRect[]>(() => {
    const data = this.ctx.data();
    const xKey = this.ctx.xKey();
    const key = this.dataKey();
    const categories = data.map((d) => String(d[xKey]));
    const keys = this.ctx.seriesKeys();
    const count = Math.max(1, keys.length);
    const index = Math.max(0, keys.indexOf(key));
    const stacked = this.ctx.stacked() && count > 1;
    const r = this.radius();
    const base = stacked ? this.ctx.stackBaseFor(key) : undefined;
    const [, max] = this.ctx.yDomain();

    if (this.horizontal()) {
      const band = bandScale(
        categories,
        [this.ctx.plotTop(), this.ctx.plotBottom()],
        0.2,
      );
      const vScale = linearScale(
        [0, max],
        [this.ctx.plotLeft(), this.ctx.plotRight()],
      );
      const zero = vScale(0);
      const subH = band.bandwidth / count;
      return data.map((d, i) => {
        const value = Number(d[key] ?? 0);
        let x: number, y: number, width: number, height: number;
        if (stacked) {
          const lo = base?.[i] ?? 0;
          y = band(categories[i]);
          height = band.bandwidth;
          x = vScale(lo);
          width = Math.max(0, vScale(lo + value) - x);
        } else {
          y = band(categories[i]) + subH * index;
          height = Math.max(0, subH - 1);
          x = zero;
          width = Math.max(0, vScale(value) - zero);
        }
        const radii = cornerRadii(r, true, stacked, index, count);
        return {
          x,
          y,
          width,
          height,
          d: roundedRectPath(x, y, width, height, radii),
          fill: d.fill,
          name: categories[i],
          value,
        };
      });
    }

    const band = bandScale(
      categories,
      [this.ctx.plotLeft(), this.ctx.plotRight()],
      0.2,
    );
    const yScale = this.ctx.yScale();
    const baseline = yScale(0);
    const subW = band.bandwidth / count;
    return data.map((d, i) => {
      const value = Number(d[key] ?? 0);
      let x: number, y: number, width: number, height: number;
      if (stacked) {
        const lo = base?.[i] ?? 0;
        x = band(categories[i]);
        width = band.bandwidth;
        y = yScale(lo + value);
        height = Math.max(0, yScale(lo) - y);
      } else {
        x = band(categories[i]) + subW * index;
        width = Math.max(0, subW - 1);
        y = yScale(value);
        height = Math.max(0, baseline - y);
      }
      const radii = cornerRadii(r, false, stacked, index, count);
      return {
        x,
        y,
        width,
        height,
        d: roundedRectPath(x, y, width, height, radii),
        fill: d.fill,
        name: categories[i],
        value,
      };
    });
  });

  /** Category-axis ticks (X labels when vertical, Y labels when horizontal). */
  readonly categoryTicks = computed<BarCategoryTick[]>(() => {
    const data = this.ctx.data();
    const xKey = this.ctx.xKey();
    const categories = data.map((d) => String(d[xKey]));
    if (this.horizontal()) {
      const band = bandScale(
        categories,
        [this.ctx.plotTop(), this.ctx.plotBottom()],
        0.2,
      );
      const x = Math.max(0, this.ctx.plotLeft() - 8);
      return categories.map((label) => ({
        label,
        x,
        y: band(label) + band.bandwidth / 2,
      }));
    }
    const band = bandScale(
      categories,
      [this.ctx.plotLeft(), this.ctx.plotRight()],
      0.2,
    );
    const y = this.ctx.plotBottom() + 16;
    return categories.map((label) => ({
      label,
      x: band(label) + band.bandwidth / 2,
      y,
    }));
  });

  /** Numeric value-axis ticks (Y when vertical, X when horizontal). */
  readonly valueTicks = computed<BarValueTick[]>(() => {
    const [, max] = this.ctx.yDomain();
    const ticks = computeTicks(max, 4);
    if (this.horizontal()) {
      const vScale = linearScale(
        [0, max],
        [this.ctx.plotLeft(), this.ctx.plotRight()],
      );
      const y = this.ctx.plotBottom() + 16;
      return ticks.map((value) => ({
        value,
        label: formatValue(value, 'number'),
        x: vScale(value),
        y,
      }));
    }
    const yScale = this.ctx.yScale();
    const x = Math.max(0, this.ctx.plotLeft() - 6);
    return ticks.map((value) => ({
      value,
      label: formatValue(value, 'number'),
      x,
      y: yScale(value),
    }));
  });

  /** Grid lines aligned to the value ticks (horizontal lines when vertical). */
  readonly gridLines = computed<BarGridLine[]>(() => {
    const [, max] = this.ctx.yDomain();
    const ticks = computeTicks(max, 4);
    if (this.horizontal()) {
      const vScale = linearScale(
        [0, max],
        [this.ctx.plotLeft(), this.ctx.plotRight()],
      );
      const y1 = this.ctx.plotTop();
      const y2 = this.ctx.plotBottom();
      return ticks.map((v) => ({ x1: vScale(v), x2: vScale(v), y1, y2 }));
    }
    const yScale = this.ctx.yScale();
    const x1 = this.ctx.plotLeft();
    const x2 = this.ctx.plotRight();
    return ticks.map((v) => ({ x1, x2, y1: yScale(v), y2: yScale(v) }));
  });

  ngOnInit(): void {
    const key = this.dataKey();
    this.ctx.register({
      key,
      values: () => this.ctx.data().map((row) => Number(row[key])),
    });
  }

  ngOnDestroy(): void {
    this.ctx.unregister(this.dataKey());
  }
}

/**
 * Per-corner radii for a bar segment, mirroring recharts. Non-stacked rounds the
 * top (vertical) or right (horizontal); stacked rounds only the outer segment.
 */
export function cornerRadii(
  r: number,
  horizontal: boolean,
  stacked: boolean,
  index: number,
  count: number,
): CornerRadii {
  if (r <= 0) return [0, 0, 0, 0];
  if (!stacked) return horizontal ? [0, r, r, 0] : [r, r, 0, 0];
  const last = count - 1;
  if (horizontal) {
    if (index === 0) return [r, 0, 0, r];
    if (index === last) return [0, r, r, 0];
    return [0, 0, 0, 0];
  }
  if (index === 0) return [0, 0, r, r];
  if (index === last) return [r, r, 0, 0];
  return [0, 0, 0, 0];
}

import {
  computed,
  Directive,
  inject,
  input,
  type OnDestroy,
  type OnInit,
} from '@angular/core';
import { ChartContext } from './chart-context';
import { linearScale } from './scales';

export interface ScatterPoint {
  cx: number;
  cy: number;
}

export interface ScatterXTick {
  x: number;
  label: string;
}

/**
 * Computes scatter points for one Y series against a numeric X field on a `<g>`
 * inside a `[chartFrame]` SVG. X uses a linear scale over the data's X extent;
 * Y uses the shared scale. Self-registers Y values for the shared domain.
 *
 * @example
 * ```html
 * <svg:g [scatter]="'score'" #s="scatter">
 *   @for (p of s.points(); track $index) { <svg:circle ... /> }
 * </svg:g>
 * ```
 */
@Directive({
  selector: 'g[scatter]',
  host: { 'data-slot': 'scatter' },
  exportAs: 'scatter',
})
export class Scatter implements OnInit, OnDestroy {
  private readonly ctx = inject(ChartContext);

  readonly dataKey = input.required<string>({ alias: 'scatter' });

  /** Linear X scale over the data's X extent, mapped into the plot width. */
  private readonly xScale = computed(() => {
    const xs = this.ctx.data().map((d) => Number(d[this.ctx.xKey()]));
    const lo = xs.length ? Math.min(...xs) : 0;
    const hi = xs.length ? Math.max(...xs) : 1;
    return linearScale(lo === hi ? [lo, lo + 1] : [lo, hi], [
      this.ctx.plotLeft(),
      this.ctx.plotRight(),
    ]);
  });

  readonly points = computed<ScatterPoint[]>(() => {
    const xKey = this.ctx.xKey();
    const xScale = this.xScale();
    const yScale = this.ctx.yScale();
    return this.ctx.data().map((d) => ({
      cx: xScale(Number(d[xKey])),
      cy: yScale(Number(d[this.dataKey()])),
    }));
  });

  /** Min / mid / max numeric labels for the X axis. */
  readonly xTicks = computed<ScatterXTick[]>(() => {
    const xs = this.ctx.data().map((d) => Number(d[this.ctx.xKey()]));
    if (xs.length === 0) return [];
    const lo = Math.min(...xs);
    const hi = Math.max(...xs);
    const xScale = this.xScale();
    const values = lo === hi ? [lo] : [lo, (lo + hi) / 2, hi];
    return values.map((v) => ({ x: xScale(v), label: String(Math.round(v)) }));
  });

  /** Y baseline for X tick labels, inside the bottom gutter. */
  readonly labelY = computed(() => this.ctx.plotBottom() + 16);

  ngOnInit(): void {
    const key = this.dataKey();
    this.ctx.register({
      key,
      values: () => this.ctx.data().map((row) => Number(row[key])),
    });
  }

  ngOnDestroy(): void {
    this.ctx.unregister(this.dataKey());
  }
}

/** Center + radius for a radial chart inside a width x height box. */
export interface PolarLayout {
  cx: number;
  cy: number;
  radius: number;
}

/** Compute the center and a radius that fits the box, minus padding for labels. */
export function polarLayout(
  width: number,
  height: number,
  pad = 8,
): PolarLayout {
  return {
    cx: width / 2,
    cy: height / 2,
    radius: Math.max(0, Math.min(width, height) / 2 - pad),
  };
}

/** Cartesian point on a circle. Angle in radians, 0 at the top, clockwise. */
export function polarPoint(
  cx: number,
  cy: number,
  radius: number,
  angle: number,
): { x: number; y: number } {
  return {
    x: cx + radius * Math.sin(angle),
    y: cy - radius * Math.cos(angle),
  };
}

/** Closed SVG polygon `d` through the given points. Empty string if < 2 points. */
export function polygonPath(
  points: readonly { x: number; y: number }[],
): string {
  if (points.length < 2) return '';
  return `M${points.map((p) => `${p.x},${p.y}`).join('L')}Z`;
}

import { computed, Directive, inject, input } from '@angular/core';
import { arc as d3Arc, pie as d3Pie, type PieArcDatum } from 'd3-shape';
import { ChartContext } from './chart-context';
import { polarLayout } from './polar';

export interface PieSlice {
  d: string;
  index: number;
  name: string;
  value: number;
}

/** Centroid label position for a slice (relative to the centered `<g>`). */
export interface PieLabel {
  x: number;
  y: number;
  index: number;
  name: string;
  value: number;
}

/**
 * Computes pie/donut slices on a `<g>` inside a `[chartFrame]` SVG. The slice
 * value is `[pie]` (a data field); the slice name is the frame's `xKey`. Set
 * `innerRadiusRatio` > 0 for a donut. Apply the directive's `transform` to the
 * `<g>` so the pie is centered.
 *
 * @example
 * ```html
 * <svg:g [pie]="'visitors'" #p="pie" [attr.transform]="p.transform()">
 *   @for (s of p.slices(); track s.name) { <svg:path [attr.d]="s.d" ... /> }
 * </svg:g>
 * ```
 */
@Directive({
  selector: 'g[pie]',
  host: { 'data-slot': 'pie' },
  exportAs: 'pie',
})
export class Pie {
  private readonly ctx = inject(ChartContext);

  readonly valueKey = input.required<string>({ alias: 'pie' });
  /** 0 = full pie; e.g. 0.6 = donut with a hole at 60% of the radius. */
  readonly innerRadiusRatio = input<number>(0);

  private readonly layout = computed(() =>
    polarLayout(this.ctx.width(), this.ctx.height(), 8),
  );

  /** Pie center + radius (absolute SVG coords) — for label/tooltip positioning. */
  readonly center = computed(() => this.layout());

  /** Translate to apply to the host `<g>` so (0,0) is the pie center. */
  readonly transform = computed(
    () => `translate(${this.layout().cx},${this.layout().cy})`,
  );

  /** Arcs + the configured arc generator, shared by `slices` and `labels`. */
  private readonly geometry = computed(() => {
    const data = this.ctx.data();
    const nameKey = this.ctx.xKey();
    const valueKey = this.valueKey();
    const values = data.map((d) => Number(d[valueKey]));
    const arcs = d3Pie<number>().sort(null)(values);
    const radius = this.layout().radius;
    const gen = d3Arc<PieArcDatum<number>>()
      .innerRadius(radius * this.innerRadiusRatio())
      .outerRadius(radius);
    const names = data.map((d) => String(d[nameKey] ?? ''));
    return { arcs, gen, values, names };
  });

  readonly slices = computed<PieSlice[]>(() => {
    const { arcs, gen, values, names } = this.geometry();
    return arcs.map((a, i) => ({
      d: gen(a) ?? '',
      index: i,
      name: names[i] ?? '',
      value: values[i],
    }));
  });

  /** Centroid label positions (relative to the centered `<g>`) for `showLabels`. */
  readonly labels = computed<PieLabel[]>(() => {
    const { arcs, gen, values, names } = this.geometry();
    return arcs.map((a, i) => {
      const [x, y] = gen.centroid(a);
      return { x, y, index: i, name: names[i] ?? '', value: values[i] };
    });
  });
}

import {
  computed,
  Directive,
  inject,
  input,
  type OnDestroy,
  type OnInit,
} from '@angular/core';
import { ChartContext } from './chart-context';
import { polarLayout, polarPoint, polygonPath } from './polar';

export interface RadarAxis {
  x2: number;
  y2: number;
  label: string;
  lx: number;
  ly: number;
}

/**
 * Computes a closed radar polygon for one series on a `<g>` inside a
 * `[chartFrame]` SVG. Categories radiate as spokes (one per data row, by the
 * frame's `xKey`); the value maps to distance along each spoke. Self-registers
 * values so all series share the same radial max. Exposes `axes()`/`rings()`
 * (the same for every series) — render them once (e.g. for the first series).
 *
 * @example `<svg:g [radar]="'desktop'" #r="radar"><svg:path [attr.d]="r.d()"/></svg:g>`
 */
@Directive({
  selector: 'g[radar]',
  host: { 'data-slot': 'radar' },
  exportAs: 'radar',
})
export class Radar implements OnInit, OnDestroy {
  private readonly ctx = inject(ChartContext);

  readonly dataKey = input.required<string>({ alias: 'radar' });
  readonly color = input<string>('currentColor');

  private readonly layout = computed(() =>
    polarLayout(this.ctx.width(), this.ctx.height(), 28),
  );

  readonly center = computed(() => this.layout());

  readonly d = computed(() => {
    const data = this.ctx.data();
    const n = data.length;
    if (n === 0) return '';
    const [, max] = this.ctx.yDomain();
    const { cx, cy, radius } = this.layout();
    const points = data.map((row, i) => {
      const angle = (i / n) * 2 * Math.PI;
      const r = (Number(row[this.dataKey()]) / max) * radius;
      return polarPoint(cx, cy, r, angle);
    });
    return polygonPath(points);
  });

  /** Spoke endpoints + category labels (shared across series). */
  readonly axes = computed<RadarAxis[]>(() => {
    const data = this.ctx.data();
    const n = data.length;
    const { cx, cy, radius } = this.layout();
    return data.map((row, i) => {
      const angle = (i / n) * 2 * Math.PI;
      const end = polarPoint(cx, cy, radius, angle);
      const label = polarPoint(cx, cy, radius + 14, angle);
      return {
        x2: end.x,
        y2: end.y,
        label: String(row[this.ctx.xKey()]),
        lx: label.x,
        ly: label.y,
      };
    });
  });

  /** Concentric reference rings (shared across series). */
  readonly rings = computed<string[]>(() => {
    const data = this.ctx.data();
    const n = data.length;
    if (n === 0) return [];
    const { cx, cy, radius } = this.layout();
    return [0.25, 0.5, 0.75, 1].map((level) =>
      polygonPath(
        data.map((_, i) =>
          polarPoint(cx, cy, radius * level, (i / n) * 2 * Math.PI),
        ),
      ),
    );
  });

  ngOnInit(): void {
    const key = this.dataKey();
    this.ctx.register({
      key,
      values: () => this.ctx.data().map((row) => Number(row[key])),
    });
  }

  ngOnDestroy(): void {
    this.ctx.unregister(this.dataKey());
  }
}

import { computed, Directive, inject, input } from '@angular/core';
import { arc as d3Arc } from 'd3-shape';
import { ChartContext } from './chart-context';
import { polarLayout } from './polar';

export interface RadialArc {
  /** Value arc (sweep proportional to the value). */
  d: string;
  /** Full-circle track behind the value arc. */
  track: string;
  index: number;
  name: string;
  value: number;
}

interface ArcInput {
  innerRadius: number;
  outerRadius: number;
  startAngle: number;
  endAngle: number;
}

/**
 * Computes concentric radial bars on a `<g>` inside a `[chartFrame]` SVG — one
 * ring per data row, sweep proportional to its `[radialBar]` value (relative to
 * the largest value). Apply the directive's `transform` to center the `<g>`.
 *
 * @example
 * ```html
 * <svg:g [radialBar]="'visitors'" #r="radialBar" [attr.transform]="r.transform()">
 *   @for (a of r.arcs(); track a.name) { <svg:path [attr.d]="a.d" ... /> }
 * </svg:g>
 * ```
 */
@Directive({
  selector: 'g[radialBar]',
  host: { 'data-slot': 'radial-bar' },
  exportAs: 'radialBar',
})
export class RadialBar {
  private readonly ctx = inject(ChartContext);

  readonly valueKey = input.required<string>({ alias: 'radialBar' });

  private readonly layout = computed(() =>
    polarLayout(this.ctx.width(), this.ctx.height(), 8),
  );

  /** Center + radius (absolute SVG coords) — for tooltip positioning. */
  readonly center = computed(() => this.layout());

  readonly transform = computed(
    () => `translate(${this.layout().cx},${this.layout().cy})`,
  );

  readonly arcs = computed<RadialArc[]>(() => {
    const data = this.ctx.data();
    const n = data.length;
    if (n === 0) return [];
    const valueKey = this.valueKey();
    const nameKey = this.ctx.xKey();
    const values = data.map((d) => Number(d[valueKey]));
    const max = Math.max(...values, 1);
    const { radius } = this.layout();
    const band = radius / (n + 0.5);
    const gen = d3Arc<ArcInput>().cornerRadius(band * 0.35);

    return data.map((row, i) => {
      const outer = radius - band * i;
      const inner = outer - band * 0.7;
      const endAngle = (values[i] / max) * 2 * Math.PI;
      const base = { innerRadius: inner, outerRadius: outer, startAngle: 0 };
      return {
        d: gen({ ...base, endAngle }) ?? '',
        track: gen({ ...base, endAngle: 2 * Math.PI }) ?? '',
        index: i,
        name: String(row[nameKey]),
        value: values[i],
      };
    });
  });
}
